import java.text.NumberFormat;
import java.util.Locale;

// 変数の宣言と初期化
double amount = 1234567.89;

NumberFormat nfJP = NumberFormat.getInstance(Locale.JAPAN);
System.out.println(nfJP.format(amount)); // 1,234,567.89

NumberFormat nfDE = NumberFormat.getInstance(Locale.GERMANY);
System.out.println(nfDE.format(amount)); // 1.234.567,89

NumberFormat cfJP = NumberFormat.getCurrencyInstance(Locale.JAPAN);
System.out.println(cfJP.format(amount)); // ￥1,234,568

NumberFormat cfUS = NumberFormat.getCurrencyInstance(Locale.US);
System.out.println(cfUS.format(amount)); // $1,234,567.89

import java.time.LocalDate;
import java.time.format.DateTimeFormatter;
import java.time.format.FormatStyle;
import java.util.Locale;

LocalDate date = LocalDate.of(2025, 4, 1);

DateTimeFormatter fmtJP = DateTimeFormatter
    .ofLocalizedDate(FormatStyle.FULL)
    .withLocale(Locale.JAPAN);
System.out.println(date.format(fmtJP));
// 2025年4月1日火曜日

DateTimeFormatter fmtUS = DateTimeFormatter
    .ofLocalizedDate(FormatStyle.FULL)
    .withLocale(Locale.US);
System.out.println(date.format(fmtUS));
// Tuesday, April 1, 2025

